include("shared.lua")if Pets.EnableDynamicLights then 	function ENT:Think()		self.BaseClass.Think(self)		if !IsValid(self.dlight) then			self.dlight = DynamicLight(self:EntIndex())		end		local dlight = self.dlight		dlight.Pos = self:GetPos() + Vector(0, 0, 10)		dlight.r = 255		dlight.g = 150		dlight.b = 100		dlight.Brightness = 1		dlight.MinLight = 0.05		dlight.Size = 78		dlight.Decay = 0		dlight.DieTime = CurTime() + 0.5		dlight.Style = 1	end end